// Content Post Trigger
// Triggered when PRIMARY_CELL logs a content-related task
const record = $input.first().json.record;
const payload = {
  event: 'content_post_trigger',
  agent: record.agent_name,
  task: record.task_description,
  alignment: record.mission_alignment,
  vitality: record.vitality_score,
  cycle: record.cycle_number,
  timestamp: record.pi_pulse_timestamp,
  phi_weight: record.phi_weight,
  model: record.model_used,
  tokens: record.tokens_used
};
return [{ json: payload }];

// Alert Routing
// Triggered when IMMUNE_AGENT detects a threat
const record = $input.first().json.record;
const severity = record.mission_alignment < 0.382 ? 'CRITICAL' : record.mission_alignment < 0.618 ? 'WARNING' : 'INFO';
const payload = {
  event: 'security_alert',
  severity: severity,
  agent: record.agent_name,
  task: record.task_description,
  alignment: record.mission_alignment,
  cycle: record.cycle_number,
  timestamp: record.pi_pulse_timestamp
};
return [{ json: payload }];

// Cost Threshold Alert
// Triggered when a single task exceeds $1.00 USD
const record = $input.first().json.record;
const payload = {
  event: 'cost_threshold_alert',
  agent: record.agent_name,
  model: record.model_used,
  cost_usd: record.cost_usd,
  tokens: record.tokens_used,
  phi_weight: record.phi_weight,
  cycle: record.cycle_number,
  timestamp: record.pi_pulse_timestamp
};
return [{ json: payload }];

// Evolution Event Notification
// Triggered when EVOLUTION_NODE logs a cycle
const record = $input.first().json.record;
const payload = {
  event: 'evolution_notification',
  agent: record.agent_name,
  task: record.task_description,
  alignment: record.mission_alignment,
  vitality: record.vitality_score,
  cycle: record.cycle_number,
  timestamp: record.pi_pulse_timestamp
};
return [{ json: payload }];
